namespace sv_d6d70d57e8e1475aa63514f6ff065a04.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service holding per-circuit theme state.
/// Every interactive component in the same circuit shares one instance.
/// </summary>
public sealed class ThemeService
{
    public ThemeMode Mode { get; private set; } = ThemeMode.System;
    public string AccentColor { get; private set; } = "#0d6efd";

    /// <summary>Raised whenever Mode or AccentColor changes.</summary>
    public event Action? OnChange;

    public void SetMode(ThemeMode mode)
    {
        if (Mode == mode) return;
        Mode = mode;
        OnChange?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        OnChange?.Invoke();
    }

    /// <summary>
    /// Bulk-set without raising OnChange (used during initialization from cookie).
    /// </summary>
    public void Initialize(ThemeMode mode, string accentColor)
    {
        Mode = mode;
        AccentColor = accentColor;
    }
}

// Reads persisted theme preferences from a cookie.
export function getThemePrefs() {
    const cookie = document.cookie
        .split('; ')
        .find(c => c.startsWith('theme_prefs='));
    if (!cookie) return null;
    try {
        return JSON.parse(decodeURIComponent(cookie.split('=')[1]));
    } catch {
        return null;
    }
}

// Applies theme to the document and persists to cookie.
export function applyTheme(mode, accentColor) {
    const resolved = mode === 'system'
        ? (window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light')
        : mode;

    document.documentElement.setAttribute('data-bs-theme', resolved);
    document.documentElement.style.setProperty('--app-accent-color', accentColor);

    const prefs = JSON.stringify({ mode, accentColor });
    document.cookie =
        `theme_prefs=${encodeURIComponent(prefs)};path=/;max-age=${365 * 24 * 60 * 60};SameSite=Lax`;
}

@*
    Invisible interactive island placed in the static layout.
    Initializes ThemeService from the browser cookie on first render
    and keeps the DOM in sync whenever the theme changes.
*@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService
@inject IJSRuntime JS

@code {
    private IJSObjectReference? _module;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/theme.js");

        // Read persisted prefs from cookie
        var prefs = await _module.InvokeAsync<ThemePrefs?>("getThemePrefs");
        if (prefs is not null)
        {
            if (Enum.TryParse<ThemeMode>(prefs.Mode, true, out var mode))
                ThemeService.Initialize(mode, prefs.AccentColor ?? "#0d6efd");
        }

        await ApplyThemeAsync();
        ThemeService.OnChange += HandleThemeChanged;

        // Re-render so subscribers see initialized values
        StateHasChanged();
    }

    private async void HandleThemeChanged()
    {
        await InvokeAsync(async () =>
        {
            await ApplyThemeAsync();
            StateHasChanged();
        });
    }

    private async Task ApplyThemeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync(
                "applyTheme",
                ThemeService.Mode.ToString().ToLowerInvariant(),
                ThemeService.AccentColor);
        }
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }

    private sealed record ThemePrefs(string? Mode, string? AccentColor);
}

@*
    Interactive island in the layout header that displays the
    current theme and lets the user cycle through modes.
*@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
        title="Current theme: @ThemeService.Mode">
    @Icon @ThemeService.Mode
</button>

@code {
    private string Icon => ThemeService.Mode switch
    {
        ThemeMode.Light  => "☀️",
        ThemeMode.Dark   => "🌙",
        _                => "💻"
    };

    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleChanged;
    }

    private void HandleChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private void CycleTheme()
    {
        var next = ThemeService.Mode switch
        {
            ThemeMode.Light  => ThemeMode.Dark,
            ThemeMode.Dark   => ThemeMode.System,
            _                => ThemeMode.Light
        };
        ThemeService.SetMode(next);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var mode in Enum.GetValues<ThemeMode>())
            {
                <button class="btn @(mode == ThemeService.Mode ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => ThemeService.SetMode(mode)">
                    @mode
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <div class="d-flex align-items-center gap-2 mb-3">
            <input type="color" class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="OnAccentChanged" />
            <span class="text-muted">@ThemeService.AccentColor</span>
        </div>

        <h5 class="card-title">Preview</h5>
        <p>
            Current theme: <strong>@ThemeService.Mode</strong><br />
            Accent:
            <span class="badge" style="background-color: @ThemeService.AccentColor;">
                @ThemeService.AccentColor
            </span>
        </p>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleChanged;
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeService.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");
    }

    private void HandleChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleChanged;
    }
}

