public sealed class ThemeService
{
    public ThemeMode Mode { get; private set; } = ThemeMode.System;
    public string AccentColor { get; private set; } = "#0d6efd";

    /// <summary>Raised whenever Mode or AccentColor changes.</summary>
    public event Action? OnChange;

    public void SetMode(ThemeMode mode)
    {
        if (Mode == mode) return;
        Mode = mode;
        OnChange?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        OnChange?.Invoke();
    }

    /// <summary>
    /// Bulk-set without raising OnChange (used during initialization from cookie).
    /// </summary>
    public void Initialize(ThemeMode mode, string accentColor)
    {
        Mode = mode;
        AccentColor = accentColor;
    }
}

