// Reads persisted theme preferences from a cookie.
export function getThemePrefs() {
    const cookie = document.cookie
        .split('; ')
        .find(c => c.startsWith('theme_prefs='));
    if (!cookie) return null;
    try {
        return JSON.parse(decodeURIComponent(cookie.split('=')[1]));
    } catch {
        return null;
    }
}

// Applies theme to the document and persists to cookie.
export function applyTheme(mode, accentColor) {
    const resolved = mode === 'system'
        ? (window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light')
        : mode;

    document.documentElement.setAttribute('data-bs-theme', resolved);
    document.documentElement.style.setProperty('--app-accent-color', accentColor);

    const prefs = JSON.stringify({ mode, accentColor });
    document.cookie =
        `theme_prefs=${encodeURIComponent(prefs)};path=/;max-age=${365 * 24 * 60 * 60};SameSite=Lax`;
}

