@*
    Invisible interactive island placed in the static layout.
    Initializes ThemeService from the browser cookie on first render
    and keeps the DOM in sync whenever the theme changes.
*@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService
@inject IJSRuntime JS

@code {
    private IJSObjectReference? _module;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/theme.js");

        // Read persisted prefs from cookie
        var prefs = await _module.InvokeAsync<ThemePrefs?>("getThemePrefs");
        if (prefs is not null)
        {
            if (Enum.TryParse<ThemeMode>(prefs.Mode, true, out var mode))
                ThemeService.Initialize(mode, prefs.AccentColor ?? "#0d6efd");
        }

        await ApplyThemeAsync();
        ThemeService.OnChange += HandleThemeChanged;

        // Re-render so subscribers see initialized values
        StateHasChanged();
    }

    private async void HandleThemeChanged()
    {
        await InvokeAsync(async () =>
        {
            await ApplyThemeAsync();
            StateHasChanged();
        });
    }

    private async Task ApplyThemeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync(
                "applyTheme",
                ThemeService.Mode.ToString().ToLowerInvariant(),
                ThemeService.AccentColor);
        }
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }

    private sealed record ThemePrefs(string? Mode, string? AccentColor);
}

